local pgmoon = require("pgmoon")

local function connect_db()
    local pg = pgmoon.new({
        host = os.getenv("DB_HOST") or "127.0.0.1",
        port = os.getenv("DB_PORT") or "5432",
        database = os.getenv("DB_NAME") or "myapp",
        user = os.getenv("DB_USER") or "postgres",
        password = os.getenv("DB_PASSWORD") or "postgres",
    })

    local ok, err = pg:connect()
    if not ok then
        return nil, "Failed to connect to database: " .. (err or "unknown error")
    end

    return pg
end

local function escape_literal(pg, value)
    if value == nil then
        return "NULL"
    end
    return pg:escape_literal(tostring(value))
end

local function validate_integer(value)
    if value == nil or value == "" then
        return nil, "missing value"
    end

    local sanitized = string.match(value, "^%s*(-?%d+)%s*$")
    if not sanitized then
        return nil, "invalid integer value"
    end

    local num = tonumber(sanitized)
    if not num or num ~= math.floor(num) then
        return nil, "value is not a valid integer"
    end

    return num, nil
end

local function send_json_response(status, data)
    ngx.status = status
    ngx.header["Content-Type"] = "application/json; charset=utf-8"

    local cjson = require("cjson.safe")
    local body = cjson.encode(data)
    ngx.say(body)
    return ngx.exit(status)
end

