        })
    end

    local pg, db_err = connect_db()
    if not pg then
        ngx.log(ngx.ERR, db_err)
        return send_json_response(ngx.HTTP_INTERNAL_SERVER_ERROR, {
            error = "Database connection failed"
        })
    end

    -- Use parameterized query via escape_literal to prevent SQL injection.
    -- NEVER do: "SELECT * FROM users WHERE id=" .. user_id
